import React, { useContext, useState } from 'react';
import { Link } from 'react-router-dom';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import {
  BarChart, Bar, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LineChart, Line
} from 'recharts';
import {
  Play, AlertTriangle, TrendingDown, Cpu, HardDrive,
  Network, Database, Shield, Boxes, Cloud,
} from 'lucide-react';
import { AppCtx } from '../App';
import {
  fetchFindingsSummary, fetchRuns, runAnalysis,
} from '../api/azure';
import api from '../api/client';
import AssetIcon from '../components/AssetIcon';
import SyncButton from '../components/SyncButton';
import AdminOnly from '../components/AdminOnly';
import ActionMessage from '../components/ActionMessage';
import useResourceSync from '../hooks/useResourceSync';
import { PAGE_ICONS } from '../config/assetIcons';
import { toDisplayNumber } from '../utils/formatDisplay';
import { getErrorMessage } from '../api/errors';
import { formatCurrency } from '../utils/format';
import { formatChartAxis } from '../utils/costCurrency';
import PageHeader from '../components/PageHeader';

const SEV_COLORS = {
  CRITICAL: '#dc2626', HIGH: '#f97316', MEDIUM: '#f59e0b', LOW: '#22c55e', INFO: '#6366f1'
};
const CAT_COLORS = ['#2563eb','#7c3aed','#0891b2','#059669','#d97706','#dc2626','#6366f1','#0d9488'];

const fetchResourceCounts = (sub) =>
  api.get('/resources/counts', { params: { subscription_id: sub } }).then((r) => r.data);

export default function Dashboard() {
  const { subscription, billingCurrency } = useContext(AppCtx);
  const queryClient = useQueryClient();
  const [running, setRunning] = useState(false);
  const [runMsg, setRunMsg]   = useState('');
  const [engineVersion, setEngineVersion] = useState('extended');
  const [profile, setProfile] = useState('default');
  const [dataSource, setDataSource] = useState('db');
  const [includeMetrics, setIncludeMetrics] = useState(false);

  const invalidateAnalysisQueries = () => {
    if (!subscription) return;
    queryClient.invalidateQueries({ queryKey: ['findings-index', subscription] });
    queryClient.invalidateQueries({ queryKey: ['findings-summary', subscription] });
    queryClient.invalidateQueries({ queryKey: ['findings', subscription] });
    queryClient.invalidateQueries({ queryKey: ['runs', subscription] });
    queryClient.invalidateQueries({ queryKey: ['vms', subscription] });
    queryClient.invalidateQueries({ queryKey: ['aks', subscription] });
    queryClient.invalidateQueries({ queryKey: ['/resources', subscription] });
  };

  const { sync, syncing, message: syncMsg } = useResourceSync({
    subscription,
    analyzeAfterSync: true,
    engineVersion,
    invalidateKeys: [['resource-counts', subscription]],
    onAnalysisComplete: invalidateAnalysisQueries,
  });

  const { data: summary, refetch: refetchSummary } = useQuery({
    queryKey: ['findings-summary', subscription],
    queryFn:  () => fetchFindingsSummary({ subscription_id: subscription }),
    enabled:  !!subscription,
  });

  const { data: runs = [] } = useQuery({
    queryKey: ['runs', subscription],
    queryFn:  () => fetchRuns({ subscription_id: subscription, limit: 10 }),
    enabled:  !!subscription,
  });

  const { data: counts = {}, isLoading: countsLoading, isError: countsError } = useQuery({
    queryKey: ['resource-counts', subscription],
    queryFn:  () => fetchResourceCounts(subscription),
    enabled:  !!subscription,
    staleTime: 5 * 60_000,
  });

  const { data: costByService } = useQuery({
    queryKey: ['cost-by-service', subscription],
    queryFn:  () => api.get('/costs/by-service', { params: { subscription_id: subscription } }).then(r => r.data),
    enabled:  !!subscription,
  });

  const handleRun = async () => {
    if (!subscription) return;
    setRunning(true); setRunMsg('');
    try {
      const r = await runAnalysis({
        subscription_id: subscription,
        profile,
        engine_version: engineVersion,
        data_source: dataSource,
        include_metrics: dataSource === 'live' && includeMetrics,
      });
      const src = r.data_source === 'live' ? 'Azure live' : 'database';
      setRunMsg(
        '\u2713 '
        + (r.summary?.total_findings ?? 0)
        + ' findings from '
        + src
        + ' \u00b7 '
        + formatCurrency(r.summary?.total_estimated_monthly_savings_usd ?? 0, {
          currency: billingCurrency || 'CAD',
          decimals: 0,
        })
        + ' potential savings/mo',
      );
      invalidateAnalysisQueries();
      refetchSummary();
    } catch (e) {
      setRunMsg('\u2717 ' + getErrorMessage(e, 'Analysis failed. Please try again.'));
    } finally {
      setRunning(false);
    }
  };

  // KPI data from live findings summary
  const sev = summary?.by_severity || {};
  const cat = summary?.by_category  || {};
  const sevData = Object.entries(sev).map(([k, v]) => ({ name: k, value: toDisplayNumber(v) }));
  const catData = Object.entries(cat).map(([k, v]) => ({ name: k, value: toDisplayNumber(v) }));

  // Cost trend from real runs
  const runsData = [...(runs || [])].reverse().map(r => ({
    date:     new Date(r.analyzed_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
    savings:  r.total_savings_usd || 0,
    findings: r.total_findings || 0,
  }));

  // Cost by service from real Azure Cost Management API
  const svcData = (() => {
    const rows = costByService?.properties?.rows || [];
    const cols = (costByService?.properties?.columns || []).map(c => c.name);
    const svcIdx  = cols.indexOf('ServiceName');
    const pretaxIdx = cols.indexOf('PreTaxCost');
    if (svcIdx < 0 || pretaxIdx < 0) return [];
    const map = {};
    rows.forEach(r => {
      const key = r[svcIdx];
      const billing = parseFloat(r[pretaxIdx]) || 0;
      map[key] = (map[key] || 0) + billing;
    });
    return Object.entries(map)
      .map(([name, value]) => ({ name, value: Math.round(value * 100) / 100 }))
      .sort((a, b) => b.value - a.value)
      .slice(0, 8);
  })();

  const displayCurrency = billingCurrency || 'CAD';

  const resourceCategories = [
    {
      label: 'Compute',
      iconSrc: PAGE_ICONS.vms,
      icon:  <Cpu size={18} />,
      color: '#3b82f6',
      items: [
        { name: 'Virtual Machines', count: toDisplayNumber(counts.vms),   link: '/vms', iconSrc: PAGE_ICONS.vms },
        { name: 'Managed Disks',    count: toDisplayNumber(counts.disks), link: '/disks', iconSrc: PAGE_ICONS.disks },
      ],
    },
    {
      label: 'Containers',
      iconSrc: PAGE_ICONS.aks,
      icon:  <Boxes size={18} />,
      color: '#7c3aed',
      items: [
        { name: 'AKS Clusters',          count: toDisplayNumber(counts.aks), link: '/aks', iconSrc: PAGE_ICONS.aks },
        { name: 'Container Registries',  count: toDisplayNumber(counts.acr), link: '/acr', iconSrc: PAGE_ICONS.acr },
      ],
    },
    {
      label: 'App Services',
      iconSrc: PAGE_ICONS.appservices,
      icon:  <Cloud size={18} />,
      color: '#0891b2',
      items: [
        { name: 'Web / Function Apps', count: toDisplayNumber(counts.appservices), link: '/appservices', iconSrc: PAGE_ICONS.appservices },
      ],
    },
    {
      label: 'Storage',
      iconSrc: PAGE_ICONS.storage,
      icon:  <HardDrive size={18} />,
      color: '#d97706',
      items: [
        { name: 'Storage Accounts', count: toDisplayNumber(counts.storage), link: '/storage', iconSrc: PAGE_ICONS.storage },
      ],
    },
    {
      label: 'Networking',
      iconSrc: PAGE_ICONS.publicips,
      icon:  <Network size={18} />,
      color: '#059669',
      items: [
        { name: 'Public IPs',          count: toDisplayNumber(counts.publicips),  link: '/publicips', iconSrc: PAGE_ICONS.publicips },
        { name: 'Load Balancers',       count: toDisplayNumber(counts.loadbalancers),  link: '/loadbalancers', iconSrc: PAGE_ICONS.loadbalancers },
        { name: 'App Gateways',         count: toDisplayNumber(counts.appgateways),  link: '/appgateways', iconSrc: PAGE_ICONS.appgateways },
        { name: 'Network Sec. Groups',  count: toDisplayNumber(counts.nsgs), link: '/nsgs', iconSrc: PAGE_ICONS.nsgs },
      ],
    },
    {
      label: 'Databases',
      iconSrc: PAGE_ICONS.sql,
      icon:  <Database size={18} />,
      color: '#dc2626',
      items: [
        { name: 'SQL Servers',    count: toDisplayNumber(counts.sql),    link: '/sql', iconSrc: PAGE_ICONS.sql },
        { name: 'Cosmos DB',      count: toDisplayNumber(counts.cosmosdb), link: '/cosmosdb', iconSrc: PAGE_ICONS.cosmosdb },
        { name: 'PostgreSQL',     count: toDisplayNumber(counts.postgresql),     link: '/postgresql', iconSrc: PAGE_ICONS.postgresql },
      ],
    },
    {
      label: 'Security',
      iconSrc: PAGE_ICONS.keyvaults,
      icon:  <Shield size={18} />,
      color: '#f97316',
      items: [
        { name: 'Key Vaults', count: toDisplayNumber(counts.keyvaults), link: '/keyvaults', iconSrc: PAGE_ICONS.keyvaults },
      ],
    },
  ];

  const totalResources = Object.values(counts || {}).reduce(
    (sum, n) => sum + toDisplayNumber(n),
    0,
  );
  const openFindings = toDisplayNumber(summary?.open_findings);
  const estSavings = toDisplayNumber(summary?.total_estimated_savings_usd);
  const criticalCount = toDisplayNumber(sev.CRITICAL);
  const highCount = toDisplayNumber(sev.HIGH);

  return (
    <div className="dashboard-page">
      <PageHeader
        title="Dashboard"
        iconSrc={PAGE_ICONS.dashboard}
        subtitle={subscription ? 'Cost and optimization overview for your subscription' : 'Select a subscription to begin'}
      >
        <div className="analysis-bar">
          <select value={dataSource} onChange={e => setDataSource(e.target.value)} aria-label="Data source">
            <option value="db">Analyze from database</option>
            <option value="live">Analyze from Azure (admin)</option>
          </select>
          <select value={engineVersion} onChange={e => setEngineVersion(e.target.value)} aria-label="Engine version">
            <option value="extended">Extended engine</option>
            <option value="standard">Standard engine</option>
          </select>
          <select value={profile} onChange={e => setProfile(e.target.value)} aria-label="Profile">
            <option value="default">Default profile</option>
            <option value="aggressive">Aggressive</option>
            <option value="conservative">Conservative</option>
          </select>
          {dataSource === 'live' && (
            <label className="checkbox-label">
              <input type="checkbox" checked={includeMetrics} onChange={e => setIncludeMetrics(e.target.checked)} />
              Include VM metrics
            </label>
          )}
          {runMsg && (
            <ActionMessage message={runMsg} />
          )}
          <button type="button" className="btn btn-primary" onClick={handleRun} disabled={running || !subscription}>
            {running ? <div className="spin" style={{ width: 14, height: 14, borderWidth: 2 }} /> : <Play size={14} />}
            {running ? 'Analyzing…' : 'Run analysis'}
          </button>
        </div>
        <p className="analysis-bar-hint">
          Sync saves inventory to the database. Analysis reads that data, writes recommendations to the database, and updates every resource page.
        </p>
      </PageHeader>

      {!subscription && (
        <div className="card" style={{ textAlign: 'center', padding: '3rem', color: 'var(--text3)' }}>
          <AssetIcon src={PAGE_ICONS.subscription} size={32} alt="" style={{ margin: '0 auto 1rem', display: 'block', opacity: 0.45 }} />
          <p>Select a subscription from the sidebar to begin.</p>
        </div>
      )}

      {subscription && (
        <>
          <div className="dashboard-hero">
            <div className="dashboard-hero__glow" aria-hidden="true" />
            <div className="dashboard-hero__content">
              <div>
                <p className="dashboard-hero__eyebrow">Subscription overview</p>
                <h2 className="dashboard-hero__title">
                  {totalResources.toLocaleString()} resources synced
                </h2>
                <p className="dashboard-hero__sub">
                  {openFindings.toLocaleString()} open findings · $
                  {estSavings.toLocaleString(undefined, { maximumFractionDigits: 0 })}
                  {' '}potential monthly savings
                </p>
              </div>
              <div className="dashboard-hero__metrics">
                <div className="dashboard-hero__metric">
                  <span className="dashboard-hero__metric-value" style={{ color: 'var(--success)' }}>
                    ${estSavings.toLocaleString(undefined, { maximumFractionDigits: 0 })}
                  </span>
                  <span className="dashboard-hero__metric-label">Est. savings</span>
                </div>
                <div className="dashboard-hero__metric">
                  <span className="dashboard-hero__metric-value" style={{ color: 'var(--danger)' }}>
                    {criticalCount}
                  </span>
                  <span className="dashboard-hero__metric-label">Critical</span>
                </div>
                <div className="dashboard-hero__metric">
                  <span className="dashboard-hero__metric-value">{totalResources.toLocaleString()}</span>
                  <span className="dashboard-hero__metric-label">Resources</span>
                </div>
              </div>
            </div>
          </div>

          {/* KPI row */}
          <div className="grid-4" style={{ marginBottom: '1.5rem' }}>
            <div className="stat-card success">
              <AssetIcon src={PAGE_ICONS.costs} size={22} className="stat-card__icon" alt="" fallback={<TrendingDown size={20} />} />
              <div className="stat-label">Est. monthly savings</div>
              <div className="stat-value" style={{ color: 'var(--success)' }}>
                ${estSavings.toLocaleString(undefined, { maximumFractionDigits: 0 })}
              </div>
              <div className="stat-sub">Open findings only</div>
            </div>
            <div className="stat-card danger">
              <AssetIcon src={PAGE_ICONS.findings} size={22} className="stat-card__icon" alt="" />
              <div className="stat-label">Critical findings</div>
              <div className="stat-value" style={{ color: 'var(--danger)' }}>{criticalCount}</div>
              <div className="stat-sub">Require immediate action</div>
            </div>
            <div className="stat-card warning">
              <AssetIcon src={PAGE_ICONS.costs} size={22} className="stat-card__icon" alt="" />
              <div className="stat-label">High findings</div>
              <div className="stat-value" style={{ color: 'var(--warning)' }}>{highCount}</div>
              <div className="stat-sub">Review within 7 days</div>
            </div>
            <div className="stat-card accent">
              <AssetIcon src={PAGE_ICONS.dashboard} size={22} className="stat-card__icon" alt="" />
              <div className="stat-label">Total open</div>
              <div className="stat-value">{openFindings}</div>
              <div className="stat-sub">Across all categories</div>
            </div>
          </div>

          {/* Resource category tiles */}
          <div className="dashboard-section">
            <div className="dashboard-section__header">
              <div>
                <h3 className="dashboard-section__title">Azure resources by category</h3>
                <p className="dashboard-section__sub">Browse inventory synced to the database</p>
              </div>
              <div className="dashboard-section__actions">
                <ActionMessage message={syncMsg} />
                {countsError && (
                  <span className="analysis-bar__msg analysis-bar__msg--err">Could not load resource counts</span>
                )}
                <AdminOnly>
                  <SyncButton onClick={sync} syncing={syncing} disabled={!subscription} />
                </AdminOnly>
              </div>
            </div>
            <div className="resource-tile-grid">
              {resourceCategories.map(cat => (
                <div
                  key={cat.label}
                  className="resource-tile"
                  style={{ '--tile-accent': cat.color }}
                >
                  <div className="resource-tile__header">
                    <AssetIcon src={cat.iconSrc} size={20} alt="" fallback={cat.icon} />
                    <span>{cat.label}</span>
                  </div>
                  <ul className="resource-tile__list">
                    {cat.items.map(item => (
                      <li key={item.name}>
                        <Link to={item.link} className="resource-tile__link">
                          <AssetIcon src={item.iconSrc} size={14} alt="" />
                          <span>{item.name}</span>
                        </Link>
                        <span className={`resource-tile__count${item.count > 0 ? ' resource-tile__count--active' : ''}`}>
                          {countsLoading ? '…' : item.count}
                        </span>
                      </li>
                    ))}
                  </ul>
                </div>
              ))}
            </div>
          </div>

          {/* Charts row */}
          <div className="grid-2 dashboard-charts">
            <div className="card chart-card">
              <div className="chart-card__title">Open findings by severity</div>
              {sevData.length === 0 ? (
                <div className="empty-state" style={{ padding: '2rem' }}>
                  <AlertTriangle size={24} />
                  <p style={{ fontSize: '0.82rem' }}>No data &mdash; run analysis first</p>
                </div>
              ) : (
                <ResponsiveContainer width="100%" height={200}>
                  <PieChart>
                    <Pie data={sevData} dataKey="value" nameKey="name" cx="50%" cy="50%" outerRadius={78}
                      label={({ name, value }) => name + ': ' + value}>
                      {sevData.map(e => <Cell key={e.name} fill={SEV_COLORS[e.name] || '#6366f1'} />)}
                    </Pie>
                    <Tooltip
                      formatter={(v) => [v, 'Findings']}
                      contentStyle={{ background: 'var(--bg2)', border: '1px solid var(--border)', borderRadius: 8 }}
                    />
                  </PieChart>
                </ResponsiveContainer>
              )}
            </div>

            <div className="card chart-card">
              <div className="chart-card__title">Open findings by category</div>
              {catData.length === 0 ? (
                <div className="empty-state" style={{ padding: '2rem' }}>
                  <AlertTriangle size={24} />
                  <p style={{ fontSize: '0.82rem' }}>No data &mdash; run analysis first</p>
                </div>
              ) : (
                <ResponsiveContainer width="100%" height={200}>
                  <BarChart data={catData} margin={{ top: 0, right: 0, bottom: 24, left: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
                    <XAxis dataKey="name" tick={{ fill: 'var(--text3)', fontSize: 11 }} angle={-25} textAnchor="end" />
                    <YAxis tick={{ fill: 'var(--text3)', fontSize: 11 }} />
                    <Tooltip contentStyle={{ background: 'var(--bg2)', border: '1px solid var(--border)', borderRadius: 8 }} />
                    <Bar dataKey="value" radius={[4, 4, 0, 0]}>
                      {catData.map((e, i) => <Cell key={i} fill={CAT_COLORS[i % CAT_COLORS.length]} />)}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              )}
            </div>
          </div>

          {/* Cost by Azure service */}
          {svcData.length > 0 && (
            <div className="card chart-card" style={{ marginBottom: '1.5rem' }}>
              <div className="chart-card__title">MTD cost by Azure service ({displayCurrency})</div>
              <ResponsiveContainer width="100%" height={200}>
                <BarChart data={svcData} margin={{ top: 0, right: 0, bottom: 40, left: 10 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
                  <XAxis dataKey="name" tick={{ fill: 'var(--text3)', fontSize: 11 }} angle={-30} textAnchor="end" />
                  <YAxis tick={{ fill: 'var(--text3)', fontSize: 11 }} tickFormatter={v => formatChartAxis(v, displayCurrency)} />
                  <Tooltip
                    contentStyle={{ background: 'var(--bg2)', border: '1px solid var(--border)', borderRadius: 8 }}
                    formatter={v => [formatCurrency(v, { currency: displayCurrency }), `Cost (${displayCurrency})`]}
                  />
                  <Bar dataKey="value" fill="#3b82f6" radius={[4, 4, 0, 0]}>
                    {svcData.map((_, i) => <Cell key={i} fill={CAT_COLORS[i % CAT_COLORS.length]} />)}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          )}

          {/* Savings trend */}
          {runsData.length > 0 && (
            <div className="card chart-card">
              <div className="chart-card__title">Savings trend across analysis runs</div>
              <ResponsiveContainer width="100%" height={180}>
                <LineChart data={runsData}>
                  <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
                  <XAxis dataKey="date" tick={{ fill: 'var(--text3)', fontSize: 11 }} />
                  <YAxis tick={{ fill: 'var(--text3)', fontSize: 11 }} tickFormatter={v => formatChartAxis(v, displayCurrency)} />
                  <Tooltip
                    contentStyle={{ background: 'var(--bg2)', border: '1px solid var(--border)', borderRadius: 8 }}
                    formatter={v => [formatCurrency(v, { currency: displayCurrency }), `Est. savings (${displayCurrency})`]}
                  />
                  <Line type="monotone" dataKey="savings" stroke="#22c55e" strokeWidth={2} dot={{ fill: '#22c55e' }} />
                </LineChart>
              </ResponsiveContainer>
            </div>
          )}
        </>
      )}
    </div>
  );
}
